package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

public class CSVFormatTest {

    private void setFinalStatic(Field field, Object newValue) throws Exception {
        field.setAccessible(true);

        // Remove final modifier from field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

        field.set(null, newValue);
    }

    @Test
    void testGetHeaderWhenHeaderIsNull() throws Exception {
        // Create a CSVFormat instance with header set to null using withHeader(null)
        CSVFormat format = CSVFormat.DEFAULT.withHeader((String[]) null);

        String[] header = format.getHeader();
        assertNull(header, "Expected null header when header field is null");
    }

    @Test
    void testGetHeaderReturnsCloneNotSameArray() throws Exception {
        String[] originalHeader = new String[] {"col1", "col2", "col3"};
        CSVFormat format = CSVFormat.DEFAULT.withHeader(originalHeader);

        String[] header = format.getHeader();
        assertNotNull(header, "Header should not be null");
        assertArrayEquals(originalHeader, header, "Header arrays should be equal in content");
        assertNotSame(originalHeader, header, "Returned header array should be a clone, not the same instance");
    }
}
